import React from "react";
import "./nav.css";

function Nav() {
  const [isActive, setIsActive] = React.useState(false);
  function Modal() {
    if (!setOpen) {
      return <div className="pushMenu"></div>;
    } else {
      return <div className="pushMenu"></div>;
    }
  }
  return (
    <div
      style={{
        display: isActive ? "block" : "",
        display: isActive ? "none" : "",
      }}
      onClick={Modal}
      className="gg-menu-grid-o"
    ></div>
  );
}

export default Nav;

